void solve(int CASE)
{
	ll n, k; cin >> n >> k;
	var a = vector<pll>(n + 1);
	fa(i, 1, n) {
		ll x; cin >> x;
		while (x % 2 == 0)a[i].px++, x /= 2;
		while (x % 5 == 0)a[i].py++, x /= 5;
	}

	struct node {
		int id;
		ll now2, now5;
		node() :id(0), now2(0), now5(0) {}

		ll ans() const {
			return min(now2, now5);
		}
		ll next_ans(const vector<pll>& a) const {
			return min(now2 - a[id].px, now5 - a[id].py);
		}
	};

	var cal = [&](ll k)->ll {
		var j = node();
		ll ans = 0;
		fa(i, 1, n) {
			j.now2 += a[i].px, j.now5 += a[i].py;
			while (j.id < i and j.next_ans(a) >= k) {
				j.now2 -= a[j.id].px, j.now5 -= a[j.id].py;
				j.id++;
			}
			if (j.ans() >= k)ans += j.id;
		}
		return ans;
		};

	cout << cal(k) - cal(k + 1) << endl;
	return;
}
